1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE = 10;
3	const BLOCK_OF_THREE_PREMIUM = 60;
4	const BLOCK_SIZE = 3;
5	
6	const BASE_PREMIUMS: Record<string, number> = {
7	  sword: 100,
8	  amulet: 60,
9	  staff: 80,
10	  potion: 40,
11	  rune: 25,
12	};
13	
14	function isBlockOfThree(items: { type: string }[]): boolean {
15	  return items.length === BLOCK_SIZE && items.every((item) => item.type === items[0].type);
16	}
17	
18	export function quote({ items }: { items: { type: string }[]; years: number; priorContract: boolean }): { premium: number } {
19	  const base = isBlockOfThree(items)
20	    ? BLOCK_OF_THREE_PREMIUM
21	    : items.reduce((sum, item) => sum + BASE_PREMIUMS[item.type], 0);
22	  const surcharges = items.length * FIRST_INSURANCE_SURCHARGE;
23	  return { premium: base + surcharges + PROCESSING_FEE };
24	}
25	
26	export function claim(_input: unknown): unknown {
27	  return undefined;
28	}
